{"version":1,"template_key":"BAT-TH-142","label":"Déstratification d'air — Tertiaire","sections":[{"id":"general","title":"Informations générales","order":1,"fields":[{"id":"contact_name","type":"text","label":"Nom du contact sur site","required":true,"order":1,"hint":"Personne présente lors de la visite"},{"id":"contact_phone","type":"text","label":"Téléphone","required":true,"order":2,"hint":"06 / 07…"},{"id":"contact_email","type":"text","label":"E-mail","required":false,"order":3},{"id":"site_address","type":"text","label":"Adresse du site","required":true,"order":4,"mapToLegacyColumn":"worksite_address"},{"id":"site_postal_code","type":"text","label":"Code postal","required":true,"order":5,"mapToLegacyColumn":"worksite_postal_code"},{"id":"site_city","type":"text","label":"Ville","required":true,"order":6,"mapToLegacyColumn":"worksite_city"},{"id":"site_gps","type":"text","label":"Géolocalisation (lat, lng)","required":false,"order":7,"readonly":true,"editable":false,"hint":"Capturée automatiquement par le terminal"}]},{"id":"building","title":"Bâtiment / local","order":2,"fields":[{"id":"building_type","type":"select","label":"Type de bâtiment / usage","required":true,"order":1,"options":[{"value":"commerce","label":"Commerce"},{"value":"gymnase","label":"Gymnase / salle de sport"},{"value":"hall_production","label":"Hall de production"},{"value":"atelier","label":"Atelier"},{"value":"autre","label":"Autre tertiaire éligible"},{"value":"autre_hors_cible","label":"Autre (hors cible déstrat)"}]},{"id":"building_age_over_2y","type":"boolean","label":"Bâtiment de plus de 2 ans","required":true,"order":2,"hint":"Condition CEE obligatoire"},{"id":"building_is_closed","type":"boolean","label":"Local clos et couvert","required":true,"order":3,"hint":"Le bâtiment est fermé (murs + toiture)"},{"id":"insulation_quality","type":"select","label":"Qualité d'isolation","required":true,"order":4,"options":[{"value":"good","label":"Bonne (double vitrage, isolé)"},{"value":"average","label":"Moyenne"},{"value":"poor","label":"Mauvaise (simple vitrage, non isolé)"}]},{"id":"operating_mode","type":"select","label":"Mode de fonctionnement du bâtiment","required":true,"order":5,"options":[{"value":"continuous","label":"Continu (24h/24)"},{"value":"daytime","label":"Journée (8h–18h)"},{"value":"shift","label":"Posté (2×8 ou 3×8)"},{"value":"seasonal","label":"Saisonnier"}]},{"id":"building_length_m","type":"number","label":"Longueur","required":true,"order":6,"unit":"m","hint":"Mesure au sol du local principal"},{"id":"building_width_m","type":"number","label":"Largeur","required":true,"order":7,"unit":"m"},{"id":"building_height_m","type":"number","label":"Hauteur sous plafond","required":true,"order":8,"unit":"m","hint":"≥ 5 m pour éligibilité déstratification","mapToLegacyColumn":"ceiling_height_m"},{"id":"building_surface_m2","type":"calculated","label":"Surface","required":false,"order":9,"unit":"m²","formula":"building_length_m * building_width_m","readonly":true,"editable":false,"mapToLegacyColumn":"surface_m2"},{"id":"building_volume_m3","type":"calculated","label":"Volume","required":false,"order":10,"unit":"m³","formula":"building_length_m * building_width_m * building_height_m","readonly":true,"editable":false}]},{"id":"heating_system","title":"Système de chauffage","order":3,"fields":[{"id":"heating_present","type":"boolean","label":"Le local est chauffé","required":true,"order":1,"hint":"Condition CEE obligatoire"},{"id":"heating_absence_reason","type":"textarea","label":"Raison de l'absence de chauffage","required":true,"order":2,"hint":"Détail : jamais chauffé, en panne, démonté…","visibility_rules":[{"field":"heating_present","values":[false]}]},{"id":"heating_distribution_type","type":"select","label":"Type de diffusion / équipement","required":true,"order":3,"options":[{"value":"air_chaud_soufflage","label":"Air chaud / soufflage (aérotherme, rooftop, CTA)"},{"value":"rayonnement","label":"Rayonnement (tube radiant, panneaux)"},{"value":"mix_air_rayonnement","label":"Mix air chaud + rayonnement"},{"value":"chaudiere_eau","label":"Chaudière (radiateurs / réseau eau chaude)"},{"value":"electrique_direct","label":"Chauffage électrique direct"},{"value":"pac_air_air","label":"Pompe à chaleur air / air"},{"value":"pac_air_eau","label":"Pompe à chaleur air / eau"},{"value":"autre_inconnu","label":"Autre / inconnu"}],"visibility_rules":[{"field":"heating_present","values":[true]}]},{"id":"heating_energy","type":"select","label":"Énergie du générateur","required":true,"order":4,"options":[{"value":"gaz","label":"Gaz naturel"},{"value":"fioul","label":"Fioul"},{"value":"bois","label":"Bois / granulés"},{"value":"elec","label":"Électricité"},{"value":"pac","label":"Pompe à chaleur"}],"visibility_rules":[{"field":"heating_present","values":[true]}],"mapToLegacyColumn":"heating_type"},{"id":"heating_emission_mode","type":"select","label":"Mode d'émission de chaleur","required":true,"order":5,"options":[{"value":"convectif","label":"Convectif (air pulsé, aérotherme)"},{"value":"radiatif","label":"Radiatif (tubes, panneaux)"},{"value":"mixte","label":"Mixte"},{"value":"autre","label":"Autre"}],"visibility_rules":[{"field":"heating_present","values":[true]}]},{"id":"generator_covers_full_site","type":"radio","label":"Le générateur couvre la totalité du site","required":true,"order":6,"options":[{"value":"total","label":"Oui, totalité"},{"value":"partial","label":"Partiel (zones non couvertes)"}],"visibility_rules":[{"field":"heating_present","values":[true]}]},{"id":"generator_functional","type":"boolean","label":"Générateur en état de marche","required":true,"order":7,"visibility_rules":[{"field":"heating_present","values":[true]}]},{"id":"setpoint_temp_c","type":"number","label":"Température de consigne","required":true,"order":8,"unit":"°C","hint":"≥ 15 °C pour éligibilité CEE","visibility_rules":[{"field":"heating_present","values":[true]}]},{"id":"photo_generator","type":"photo","label":"Photos d