,"required":false,"order":9,"options":[{"value":"teddington_ds3","label":"Teddington DS3 (2 330 m³/h)"},{"value":"teddington_ds7","label":"Teddington DS7 (6 500 m³/h)"},{"value":"generfeu","label":"Generfeu (10 000 m³/h)"}],"hint":"Suggestion technique ; devis final par le bureau d'études"},{"id":"recommended_qty","type":"number","label":"Nombre d'appareils préconisé","required":false,"order":10,"hint":"Estimation terrain"}]},{"id":"electricity","title":"Installation électrique","order":5,"fields":[{"id":"electrical_phase","type":"radio","label":"Phasage électrique","required":true,"order":1,"options":[{"value":"mono","label":"Monophasé"},{"value":"tri","label":"Triphasé"}]},{"id":"transformer_present","type":"boolean","label":"Transformateur sur site","required":true,"order":2},{"id":"transformer_detail","type":"text","label":"Détail transformateur","required":false,"order":3,"hint":"Puissance, localisation, accès","visibility_rules":[{"field":"transformer_present","values":[true]}]},{"id":"electrical_panel_accessible","type":"boolean","label":"Tableau électrique accessible","required":true,"order":4},{"id":"electrical_panel_capacity_ok","type":"boolean","label":"Capacité du tableau suffisante pour ajout déstrat","required":true,"order":5,"hint":"Disjoncteurs disponibles / réserve ampérage"},{"id":"photo_electrical_panel","type":"photo","label":"Photos du tableau électrique","required":true,"order":6,"min_files":3,"max_files":10,"hint":"Vue fermée + ouverte + plaque / étiquettes"}]},{"id":"media","title":"Photos & preuves terrain","order":6,"fields":[{"id":"photo_exterior","type":"photo","label":"Photo(s) extérieur du bâtiment","required":true,"order":1,"min_files":1,"max_files":5,"hint":"Façade principale, enseigne si visible"},{"id":"photo_interior","type":"photo","label":"Photos intérieur du local","required":true,"order":2,"min_files":4,"max_files":15,"hint":"4 angles + hauteur visible + zones de stockage / circulation"},{"id":"photo_ceiling_height","type":"photo","label":"Photo montrant la hauteur sous plafond","required":true,"order":3,"min_files":1,"max_files":5,"hint":"Mètre laser visible si possible"},{"id":"photo_installation_plan","type":"photo","label":"Plan / croquis d'implantation","required":true,"order":4,"min_files":1,"max_files":5,"hint":"Emplacement prévu des déstratificateurs"},{"id":"photo_access","type":"photo","label":"Photos accès & contraintes","required":false,"order":5,"min_files":0,"max_files":10,"hint":"Accès toiture, nacelle, obstacles, chemins de câbles"}]},{"id":"notes","title":"Compte-rendu technicien","order":7,"fields":[{"id":"technician_comment","type":"textarea","label":"Commentaire technicien","required":true,"order":1,"hint":"Observations, difficultés, recommandations","mapToLegacyColumn":"observations"},{"id":"client_impression","type":"select","label":"Impression générale client","required":false,"order":2,"options":[{"value":"very_positive","label":"Très favorable"},{"value":"positive","label":"Favorable"},{"value":"neutral","label":"Neutre"},{"value":"reluctant","label":"Réticent"},{"value":"hostile","label":"Hostile au projet"}]},{"id":"technical_feasibility","type":"select","label":"Faisabilité technique","required":true,"order":3,"options":[{"value":"ok","label":"RAS — installation standard"},{"value":"ok_with_reserves","label":"Faisable avec réserves"},{"value":"complex","label":"Complexe — étude complémentaire"},{"value":"not_feasible","label":"Non faisable en l'état"}]},{"id":"feasibility_notes","type":"textarea","label":"Détail faisabilité / réserves","required":false,"order":4,"visibility_rules":[{"field":"technical_feasibility","values":["ok_with_reserves","complex","not_feasible"]}]}]},{"id":"eligibility","title":"Éligibilité terrain","order":8,"fields":[{"id":"elig_building_age","type":"calculated","label":"Bâtiment > 2 ans","required":false,"order":1,"formula":"building_age_over_2y","readonly":true,"editable":false,"hint":"Vrai si building_age_over_2y = true"},{"id":"elig_site_heated","type":"calculated","label":"Site chauffé","required":false,"order":2,"formula":"heating_present","readonly":true,"editable":false,"hint":"Vrai si heating_present = true"},{"id":"elig_site_closed","type":"calculated","label":"Local clos","required":false,"order":3,"formula":"building_is_closed","readonly":true,"editable":false,"hint":"Vrai si building_is_closed = true"},{"id":"elig_height_compatible","type":"calculated","label":"Hauteur ≥ 5 m","required":false,"order":4,"formula":"building_height_m >= 5","readonly":true,"editable":false,"hint":"Vrai si building_height_m >= 5"},{"id":"elig_emission_compatible","type":"calculated","label":"Émission compatible déstrat","required":false,"order":5,"formula":"heating_emission_mode IN [convectif, mixte]","readonly":true,"editable":false,"hint":"Convectif ou mixte = compatible ; radiatif seul = alerte"},{"id":"elig_destrat_not_already_present","type":"calculated","label":"Pas de déstrat déjà installé (ou hors service)","required":false,"order":6,"formula":"!existing_destrat_present OR existing_destrat_condition = broken","readonly":true,"editable":false,"hint":"Alerte si déstrat fonctionnel déjà en place"}]}]}
$BAT_TH_142_V1$::jsonb,
  now()
FROM public.technical_visit_templates t
WHERE t.template_key = 'BAT-TH-142'
